"""Idempotent helpers для создания каталогов и файлов на уровне приложения (без доменного знания)."""from __future__ import annotationsimport jsonfrom pathlib import Pathfrom typing import Anydef ensure_dir(path: Path) -> None:    """Создаёт каталог и родительские, если их нет."""    path.mkdir(parents=True, exist_ok=True)def ensure_text_file(path: Path, content: str) -> None:    """Создаёт текстовый файл с заданным содержимым, только если файл ещё не существует."""    path.parent.mkdir(parents=True, exist_ok=True)    if not path.exists():        path.write_text(content, encoding="utf-8")def ensure_json_file(path: Path, default_value: Any) -> None:    """Создаёт JSON-файл с заданным значением, только если файл ещё не существует."""    path.parent.mkdir(parents=True, exist_ok=True)    if not path.exists():        path.write_text(            json.dumps(default_value, ensure_ascii=False, indent=2),            encoding="utf-8",        )